import React, { useState, useEffect, useContext } from 'react';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';

const Appointments = () => {
  const { user } = useContext(AuthContext);
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchAppointments = async () => {
      if (!user) {
        setError('You must be logged in to view appointments.');
        setLoading(false);
        return;
      }
      try {
        const response = await axios.get('/api/bookings/user', { withCredentials: true });
        setAppointments(response.data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch appointments.');
      } finally {
        setLoading(false);
      }
    };
    fetchAppointments();
  }, [user]);

  if (loading) {
    return <p>Loading appointments...</p>;
  }

  if (error) {
    return <p className="text-red-600">{error}</p>;
  }

  if (appointments.length === 0) {
    return <p>No appointments found.</p>;
  }

  return (
    <div className="max-w-4xl mx-auto p-6 bg-green-100 rounded shadow text-black">
      <h2 className="text-2xl font-semibold mb-4 text-black">Appointments</h2>
      <table className="w-full border-collapse border border-gray-300">
        <thead>
          <tr>
            <th className="border border-gray-300 px-4 py-2 text-left">Doctor</th>
            <th className="border border-gray-300 px-4 py-2 text-left">Date & Time</th>
            <th className="border border-gray-300 px-4 py-2 text-left">Status</th>
          </tr>
        </thead>
        <tbody>
          {appointments.map((appt) => (
            <tr key={appt._id}>
              <td className="border border-gray-300 px-4 py-2">{appt.doctor?.username || appt.doctor}</td>
              <td className="border border-gray-300 px-4 py-2">{new Date(appt.appointmentDate).toLocaleString()}</td>
              <td className="border border-gray-300 px-4 py-2">{appt.status}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default Appointments;
